        self.warn_logger = ConfluentKafkaLogProducer(producer_conf, Warn_Log_Kafka_Topic_Name)

    def _error_cb(self, err):
        logger.warn("Confluent Kafka Producer Error: %s" % err)
        if err.code() == KafkaError._ALL_BROKERS_DOWN:
            logger.fatal("Confluent Kafka Producer Fatal Error: %s" % err)

    def emit(self, record):
        try:
            if isinstance(record.msg, unicode):
                encoded_msg = record.msg.encode('utf-8')
            else:
                encoded_msg = unicode(record.msg, 'utf-8').encode('utf-8')
        except UnicodeDecodeError:
            encoded_msg = record.msg

        # key = bytes(hashlib.md5(encoded_msg[:64]).hexdigest())
        key = None
        
        if record.levelname == 'WARNING':
            self.warn_logger.send(key=key, value=bytes(encoded_msg))


