OK finally, finally! Checking the path doesn't work if source and destination paths are the same which is possible as they are on different file systems. However we don't actually need to know this. 
If the hierarchy is missing we fix and try again. Either way any error in destination is raised exactly as before so no change in behaviour. Cost is not an issue because all of this only happens in an exception which is likely rare.

```
def makedirs(fs, path):
    log.warning(f"creating missing directory hierarchy for {path}")
    fs.makedirs(path)

def copy_file(src_fs, src_path, dst_fs, dst_path):
    """ extends copy_file to add directory hierarchy if does not exist
    
    key created on AWS does not automatically create parent directory hierarchy
    exists=True; copy_file fails
    """ 
    try:
        fs.copy.copy_file(src_fs, src_path, dst_fs, dst_path)
    except fs.errors.ResourceNotFound as e:
        if src_fs.exists(src_path) and not src_fs.exists(fs.path.dirname(src_path)):
            makedirs(src_fs, fs.path.dirname(src_path))
            fs.copy.copy_file(src_fs, src_path, dst_fs, dst_path)
        else:
            raise e

def copy_dir(src_fs, src_path, dst_fs, dst_path, walker=None, on_copy=None):
    """ extends copy_dir to add directory hierarchy if does not exist
    
    key created on AWS does not automatically create parent directory hierarchy
    exists=False, isempty=False, listdir works; copy_dir fails
    """ 
    try:
        fs.copy.copy_dir(src_fs, src_path, dst_fs, dst_path, walker, on_copy)
    except fs.errors.ResourceNotFound as e:
        if not src_fs.exists(src_path) and not src_fs.isempty(src_path):
            makedirs(src_fs, src_path)
            fs.copy.copy_dir(src_fs, src_path, dst_fs, dst_path, walker, on_copy)
        else:
            raise e

def exists(fs, path):
    """ extends exists to add directory hierarchy if does not exist """
    if fs.exists(path):
        return True
    if not fs.isempty(path):
        makedirs(fs.path.dirname(path))
        return True
    return False

def isdir(fs, path):
    """ extends isdir to add directory hierarchy if does not exist """
    if fs.isdir(path):
        return True
    if not fs.isempty(path):
        makedirs(fs.path.dirname(path))
        return True
    return False

```

